        return {"pass": False, "score": 0.0, "feedback": "external_services_path not provided; cannot check jira_state.json"}

    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}

    with open(jira_path) as f:
        data = json.load(f)

    required_names = ["ER-Park-04092026", "BENEFITS-Park-04092026"]

    # Collect all possible identifying strings from the Jira data
    # We look at keys, ids, names, summaries, titles — anything that could match
    all_identifiers = set()

    def extract_strings_from_issue(issue):
        """Extract all string values from an issue dict that could be a ticket name/key."""
        if not isinstance(issue, dict):
            return
        for k, v in issue.items():
            if isinstance(v, str):
                all_identifiers.add(v.strip())
            elif isinstance(v, dict):
                # Recurse one level for nested fields like 'fields'
                for kk, vv in v.items():
                    if isinstance(vv, str):
                        all_identifiers.add(vv.strip())

    if isinstance(data, dict):
        # Top-level keys might be ticket names
        all_identifiers.update(data.keys())

        # Check for 'issues' key
        if "issues" in data:
            issues = data["issues"]
            if isinstance(issues, dict):
                all_identifiers.update(issues.keys())
                for v in issues.values():
                    extract_strings_from_issue(v)
            elif isinstance(issues, list):
                for issue in issues:
                    extract_strings_from_issue(issue)

        # Also check if top-level values are issue dicts
        for key, val in data.items():
            if isinstance(val, dict):
                extract_strings_from_issue(val)
            elif isinstance(val, list):
                for item in val:
                    extract_strings_from_issue(item)
    elif isinstance(data, list):
        for issue in data:
            extract_strings_from_issue(issue)

    # Also do a brute-force text search in the raw JSON as a fallback
    raw_text = json.dumps(data)

    found = []
    missing = []
    for name in required_names:
        if name in all_identifiers or name in raw_text:
            found.append(name)
        else:
            missing.append(name)

    score = len(found) / len(required_names)

    if missing:
        sample_ids = sorted(list(all_identifiers))[:30]
        return {
            "pass": False,
            "score": score,
            "feedback": f"Missing Jira tickets: {missing}. Found tickets so far: {found}. Sample identifiers found: {sample_ids}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"Found all required Jira tickets: {required_names}"
    }

