    # Build a loose pattern: LEAVE, Pham, 04092026 (or 0409 2026, 04-09-2026, etc.)
    loose_pattern = re.compile(r'LEAVE.*Pham.*04.*09.*2026', re.IGNORECASE)

    all_keys = set()
    all_values_str = json.dumps(data)  # for deep search

    def collect_keys_from_dict(d):
        """Recursively collect all string keys and interesting string values."""
        if isinstance(d, dict):
            for k, v in d.items():
                all_keys.add(str(k))
                # Also check common fields that might hold ticket IDs
                if isinstance(v, (str,)):
                    all_keys.add(v)
                elif isinstance(v, dict):
                    # Check key/id/ticket_id/name fields
