                        if val:
                            all_keys.add(str(val))
                    collect_keys_from_dict(v)
                elif isinstance(v, list):
                    collect_keys_from_list(v)

    def collect_keys_from_list(lst):
        if isinstance(lst, list):
            for item in lst:
                if isinstance(item, dict):
                    for field in ['key', 'id', 'ticket_id', 'name', 'issue_key', 'issueKey', 'ticket']:
                        val = item.get(field)
                        if val:
                            all_keys.add(str(val))
                    collect_keys_from_dict(item)
                elif isinstance(item, str):
                    all_keys.add(item)

    if isinstance(data, dict):
        collect_keys_from_dict(data)
    elif isinstance(data, list):
        collect_keys_from_list(data)

    # Exact match first
    if required_key in all_keys:
        return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket: {required_key}"}

    # Case-insensitive match
