        data = json.load(f)

    required_key = "LEAVE-Pham-ADA-04092026"

    # Collect all possible keys/ids/summaries from the jira state in a generous manner
    all_keys = set()

    def extract_keys_from_issue(issue):
        """Extract all identifiable strings from an issue dict."""
        if not isinstance(issue, dict):
            return
        for field in ["key", "id", "ticket_id", "ticketId", "issue_key", "issueKey", "name", "summary", "title"]:
            val = issue.get(field)
            if val is not None:
                all_keys.add(str(val).strip())

    def walk(obj):
        """Recursively walk the JSON structure to find all potential ticket identifiers."""
        if isinstance(obj, dict):
            # The dict keys themselves might be ticket IDs
            for k, v in obj.items():
                all_keys.add(str(k).strip())
                extract_keys_from_issue(obj)  # treat the dict itself as a possible issue
                walk(v)
        elif isinstance(obj, list):
            for item in obj:
                if isinstance(item, dict):
                    extract_keys_from_issue(item)
                walk(item)
        elif isinstance(obj, str):
            # Could be a bare string ticket id
            all_keys.add(obj.strip())

    walk(data)

    # Direct match
    if required_key in all_keys:
        return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket: {required_key}"}

    # Case-insensitive match
    lower_keys = {k.lower(): k for k in all_keys}
    if required_key.lower() in lower_keys:
        matched = lower_keys[required_key.lower()]
        return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket (case-insensitive match): {matched}"}

    # Partial/fuzzy: check if the key appears as substring in any collected key
    for k in all_keys:
        if required_key in k or k in required_key:
            return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket (substring match): {k}"}

    # Also do a full-text search of the raw JSON string
    raw = jira_path.read_text()
    if required_key in raw:
        return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket in raw JSON text: {required_key}"}
    if required_key.lower() in raw.lower():
        return {"pass": True, "score": 1.0, "feedback": f"Found required Jira ticket in raw JSON text (case-insensitive): {required_key}"}

    sample = sorted(all_keys)[:30]
    return {"pass": False, "score": 0.0, "feedback": f"Missing Jira ticket: {required_key}. Sample of found keys/values: {sample}"}

