from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path not provided"}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}

    with open(mailbox_path) as f:
        data = json.load(f)

    emails = data.get("emails", [])

    # Find the original email from d.pham about upcoming surgery
    original_email = None
    for e in emails:
        from_addr = (e.get("from_addr", "") or "").lower()
        subject = (e.get("subject", "") or "").lower()
        if "d.pham@crestwood.edu" in from_addr and ("upcoming surgery" in subject or "surgery in june" in subject):
            original_email = e
            break

    if original_email is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find original 'Upcoming Surgery in June' email from d.pham@crestwood.edu in mailbox"}

    original_body = (original_email.get("body_text", "") or "").strip()

    # Find sent emails to p.huang
    sent_emails = [e for e in emails if (e.get("folder", "") or "").lower() == "sent"]
    huang_emails = [e for e in sent_emails if "p.huang@crestwood.edu" in (e.get("to_addr", "") or "").lower()]

    if not huang_emails:
        return {"pass": False, "score": 0.0, "feedback": "No sent email found to p.huang@crestwood.edu"}

    # Check if any look like a forward of 'Upcoming Surgery in June'
    def is_fwd_of_surgery(e):
        subj = (e.get("subject", "") or "").lower()
        body = (e.get("body_text", "") or "").lower()
        return ("upcoming surgery" in subj or "upcoming surgery" in body or 
                "surgery in june" in subj or "surgery in june" in body)

    fwd_emails = [e for e in huang_emails if is_fwd_of_surgery(e)]

    if not fwd_emails:
        return {"pass": False, "score": 0.0, "feedback": f"No forward of 'Upcoming Surgery in June' found to p.huang@crestwood.edu. Found {len(huang_emails)} email(s) to huang but none match."}

    # Now check that the forwarded email does NOT contain additional commentary
    # The forwarded email body should essentially be the original email content,
    # possibly with standard forwarding headers, but no extra commentary added.
    for fwd in fwd_emails:
        fwd_body = (fwd.get("body_text", "") or "").strip()

        if not fwd_body:
            continue

        # Remove common forwarding headers/metadata lines that email clients add
        # These are acceptable and not "commentary"
        cleaned_body = fwd_body
        # Remove lines like "---------- Forwarded message ----------"
        cleaned_body = re.sub(r'-{2,}\s*Forwarded\s+message\s*-{2,}', '', cleaned_body, flags=re.IGNORECASE)
        # Remove forwarding metadata lines (From:, Date:, Subject:, To:)
        cleaned_body = re.sub(r'^\s*(From|Date|Subject|To|Sent|Cc)\s*:.*$', '', cleaned_body, flags=re.IGNORECASE | re.MULTILINE)
        # Remove "Begin forwarded message" type headers
        cleaned_body = re.sub(r'Begin\s+forwarded\s+message', '', cleaned_body, flags=re.IGNORECASE)
        cleaned_body = cleaned_body.strip()

        # Similarly clean the original body for comparison
        cleaned_original = original_body.strip()

        # Check if the cleaned forwarded body is essentially the original content
        # or if there's significant extra text (commentary)
        # We'll check if the original content is contained in the forward
        if cleaned_original.lower() in cleaned_body.lower():
            # Now check for extra content beyond the original
            # Remove the original content and see what's left
            remaining = cleaned_body.lower().replace(cleaned_original.lower(), "").strip()
            # Remove any whitespace/punctuation artifacts
            remaining_clean = re.sub(r'[\s\n\r]+', ' ', remaining).strip()

            # If remaining text is minimal (just whitespace, signatures, or empty), it's a clean forward
            # Allow small amounts of residual text (forwarding artifacts)
            if len(remaining_clean) <= 20:
                return {"pass": True, "score": 1.0, "feedback": "Found forwarded 'Upcoming Surgery in June' email to p.huang@crestwood.edu with no additional commentary."}
            else:
                return {"pass": False, "score": 0.0, "feedback": f"Forwarded email to p.huang@crestwood.edu contains additional commentary beyond the original email content. Extra text found: '{remaining_clean[:200]}'"}
        else:
            # The original body isn't fully contained, but the forward still references surgery
            # This could be a partial forward or reformatted - be lenient
            # Check if the forward body is short and doesn't add much beyond what's expected
            # If the body is very similar to original (maybe minor formatting differences)
            orig_words = set(cleaned_original.lower().split())
            fwd_words = set(cleaned_body.lower().split())
            if len(orig_words) > 0:
                overlap = len(orig_words & fwd_words) / len(orig_words)
                extra_words = fwd_words - orig_words
                # Filter out common forwarding words
                fwd_artifacts = {"forwarded", "message", "from", "to", "date", "subject", "sent", "fwd", "fw", "original", "begin"}
                extra_words = extra_words - fwd_artifacts

                if overlap >= 0.7 and len(extra_words) <= 15:
                    return {"pass": True, "score": 1.0, "feedback": "Found forwarded 'Upcoming Surgery in June' email to p.huang@crestwood.edu with acceptable content."}
                else:
                    return {"pass": False, "score": 0.0, "feedback": f"Forwarded email to p.huang@crestwood.edu appears to contain additional commentary. Overlap with original: {overlap:.0%}, extra words: {len(extra_words)}"}

    # If we got here, all forward candidates had empty bodies or didn't match
    return {"pass": False, "score": 0.0, "feedback": "Forward candidates found but none had valid content matching the original email."}

