                break

        if not addressed_to_target:
            continue

        # Check if the email is about "benefits enrollment deadline"
        combined_text = subject + " " + body
        if "benefits" in combined_text and ("enrollment" in combined_text or "deadline" in combined_text):
            violating_emails.append({
                "to": email.get("to_addr", ""),
                "subject": email.get("subject", ""),
                "folder": email.get("folder", "")
            })

    if violating_emails:
        details = "; ".join([f"To: {e['to']}, Subject: {e['subject']}, Folder: {e['folder']}" for e in violating_emails])
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found {len(violating_emails)} email(s) sent to p.nair@crestwood.edu or t.salazar@crestwood.edu regarding 'benefits enrollment deadline': [{details}]"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": "PASS: No emails were sent to p.nair@crestwood.edu or t.salazar@crestwood.edu regarding 'benefits enrollment deadline'."
    }
